workspace.src/subscriptions.mjs:
export class SubscriptionManager {
  constructor() {
    this.listeners = {};
  }

  on(event, fn) {
    if (!this.listeners[event]) {
      this.listeners[event] = [];
    }
    this.listeners[event].push(fn);
  }

  off(event, fn) {
    if (!this.listeners[event]) return;
    const idx = this.listeners[event].indexOf(fn.toString());
    if (idx !== -1) {
      this.listeners[event].splice(idx, 1);
    }
  }

  emit(event, ...args) {
    if (!this.listeners[event]) return;
    for (const fn of this.listeners[event]) {
      fn(...args);
    }
  }

  listenerCount(event) {
    return this.listeners[event] ? this.listeners[event].length : 0;
  }
}

workspace.tests/subscriptions.test.mjs:
import { SubscriptionManager } from '../src/subscriptions.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

// Test 1: subscribe and emit works
const mgr1 = new SubscriptionManager();
const received = [];
const handler = (msg) => received.push(msg);
mgr1.on('message', handler);
mgr1.emit('message', 'hello');
mgr1.emit('message', 'world');
assert(JSON.stringify(received) === JSON.stringify(['hello', 'world']), 'Should receive [hello, world] but got ' + JSON.stringify(received));

// Test 2: unsubscribe actually removes the listener
mgr1.off('message', handler);
assert(mgr1.listenerCount('message') === 0, 'After off(), listener count should be 0 but got ' + mgr1.listenerCount('message'));
mgr1.emit('message', 'after-off');
assert(received.length === 2, 'Should not receive messages after off() but got ' + received.length + ' messages');

// Test 3: multiple listeners on same event
const mgr2 = new SubscriptionManager();
const log1 = [];
const log2 = [];
const h1 = (v) => log1.push(v);
const h2 = (v) => log2.push(v);
mgr2.on('data', h1);
mgr2.on('data', h2);
mgr2.emit('data', 'x');
assert(log1.length === 1 && log2.length === 1, 'Both listeners should fire');
mgr2.off('data', h1);
mgr2.emit('data', 'y');
assert(log1.length === 1, 'h1 should not fire after off, got ' + log1.length);
assert(log2.length === 2, 'h2 should still fire, got ' + log2.length);
assert(mgr2.listenerCount('data') === 1, 'Should have 1 listener remaining but got ' + mgr2.listenerCount('data'));

// Test 4: events are independent
const mgr3 = new SubscriptionManager();
const aEvents = [];
const bEvents = [];
mgr3.on('a', (v) => aEvents.push(v));
mgr3.on('b', (v) => bEvents.push(v));
mgr3.emit('a', 1);
mgr3.emit('b', 2);
assert(aEvents.length === 1 && bEvents.length === 1, 'Events should be independent');
assert(aEvents[0] === 1 && bEvents[0] === 2, 'Each event should receive its own data');

// Test 5: off() on non-existent event does not throw
mgr3.off('nonexistent', () => {});

// Test 6: emit on event with no listeners does not throw
mgr3.emit('nonexistent', 'data');

console.log('ALL TESTS PASSED');
